"""Vector store configuration for knowledge base."""
import os
from langchain_pinecone import Pinecone
from langchain_openai import OpenAIEmbeddings

# Initialize embeddings
embeddings = OpenAIEmbeddings(
    model="text-embedding-3-small"
)

# Initialize Pinecone
pinecone_index = Pinecone(
    index_name=os.getenv("PINECONE_INDEX", "knowledge-base"),
    embedding=embeddings
)

def query_vectorstore(query: str, k: int = 5):
    """Query the vector store for similar documents."""
    return pinecone_index.similarity_search(query, k=k)

def add_documents(documents):
    """Add documents to the vector store."""
    return pinecone_index.add_documents(documents)
